# 设计工具注册中心（ToolRegistry类）
class ToolRegistry:
    def __init__(self):
        self.tools = {}

    def register_tool(self, tool_name, tool_func):
        self.tools[tool_name] = tool_func

    def get_tool(self, tool_name):
        return self.tools.get(tool_name)


# 实现函数调用流程（FunctionCaller类）
class FunctionCaller:
    def __init__(self, tool_registry):
        self.tool_registry = tool_registry

    def call_function(self, tool_name, params):
        tool_func = self.tool_registry.get_tool(tool_name)
        if tool_func:
            return tool_func(**params)
        else:
            raise ValueError(f"工具'{tool_name}'未注册")


# 开发参数解析器（ParameterParser类）
class ParameterParser:
    def parse_params(self, params_str):
        params = {}
        for param in params_str.split(','):
            key, value = param.split('=')
            params[key.strip()] = value.strip()
        return params


# 实现结果反馈机制（ResultFeedback类）
class ResultFeedback:
    def feedback(self, result):
        print(f"结果：{result}")


# 示例工具函数
def add(a, b):
    return a + b

def subtract(a, b):
    return a - b


# 注册工具函数
registry = ToolRegistry()
registry.register_tool('add', add)
registry.register_tool('subtract', subtract)

# 创建函数调用者和参数解析器
caller = FunctionCaller(registry)
parser = ParameterParser()
feedback = ResultFeedback()

# 测试调用函数
